#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b){ return (*(long long*)a > *(long long*)b) - (*(long long*)a < *(long long*)b); }
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *xs = (long long*)malloc(N*sizeof(long long));
        long long *ys = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld %lld", &xs[i], &ys[i]);
        qsort(xs, N, sizeof(long long), cmp);
        qsort(ys, N, sizeof(long long), cmp);
        long long lowX, highX, lowY, highY;
        if(N%2==1){
            lowX = highX = xs[N/2];
            lowY = highY = ys[N/2];
        } else {
            lowX = xs[N/2 - 1];
            highX = xs[N/2];
            lowY = ys[N/2 - 1];
            highY = ys[N/2];
        }
        long long cntX = highX - lowX + 1;
        long long cntY = highY - lowY + 1;
        printf("%lld\n", cntX * cntY);
        free(xs); free(ys);
    }
    return 0;
}

